// MARK: - Certificate Pinning URL Session Delegate

final class CertificatePinningDelegate: NSObject, URLSessionDelegate {
    
    private let pinnedCertificateHashes: Set<String>
    
    init(pinnedHashes: Set<String>) {
        self.pinnedCertificateHashes = pinnedHashes
        super.init()
    }
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var pinningSucceeded = false
        
        for i in 0..<certificateCount {
            guard let certificate = SecTrustGetCertificateAtIndex(serverTrust, i) else { continue }
            let certData = SecCertificateCopyData(certificate) as Data
            let hash = sha256Hash(data: certData)
            
            if pinnedCertificateHashes.contains(hash) {
                pinningSucceeded = true
                break
            }
        }
        
        if pinningSucceeded {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
    
    private func sha256Hash(data: Data) -> String {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}

// MARK: - API Client

enum APIError: Error, LocalizedError {
    case deviceCompromised(reasons: [String])
    case authenticationRequired
    case networkError(Error)
    case invalidResponse
    case serverError(Int, String?)
    case rateLimited
    case insufficientFunds
    case invalidOrder
    case marketClosed
    case biometricFailed
    case sslPinningFailed
    
    var errorDescription: String? {
        switch self {
        case .deviceCompromised(let reasons):
            return "Device integrity check failed: \(reasons.joined(separator: ", "))"
        case .authenticationRequired:
            return "Authentication required"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .invalidResponse:
            return "Invalid server response"
        case .serverError(let code, let message):
            return "Server error \(code): \(message ?? "Unknown")"
        case .rateLimited:
            return "Too many requests. Please try again later."
        case .insufficientFunds:
            return "Insufficient funds for this transaction"
        case .invalidOrder:
            return "Invalid order parameters"
        case .marketClosed:
            return "Market is currently closed"
        case .biometricFailed:
            return "Biometric authentication failed"
        case .sslPinningFailed:
            return "Secure connection could not be established"
        }
    }
}

