    ]
    
    private lazy var pinningDelegate = CertificatePinningDelegate(pinnedHashes: pinnedCertHashes)
    
    private lazy var session: URLSession = {
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.urlCache = nil
        config.requestCachePolicy = .reloadIgnoringLocalAndRemoteCacheData
        return URLSession(configuration: config, delegate: pinningDelegate, delegateQueue: nil)
    }()
    
    private let rateLimiter = RateLimiter(maxRequests: 30, timeWindow: 60)
    private let requestSigner = RequestSigner()
    
    private init() {}
    
    func performAuthenticatedRequest<T: Decodable>(
        endpoint: String,
        method: String = "GET",
        body: [String: Any]? = nil,
        requiresIntegrityCheck: Bool = false,
        requiredIntegrityLevel: DeviceIntegrityChecker.RiskLevel = .none
    ) async throws -> T {
        
        // Rate limiting
        guard rateLimiter.allowRequest() else {
            throw APIError.rateLimited
        }
        
        // Device integrity check for sensitive operations
        if requiresIntegrityCheck {
            let integrityResult = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
            if integrityResult.riskLevel > requiredIntegrityLevel {
                AuditLogger.shared.log(event: .integrityCheckFailed(reasons: integrityResult.reasons))
                throw APIError.deviceCompromised(reasons: integrityResult.reasons)
            }
        }
        
        // Retrieve auth token
        guard let token = SecureStorage.shared.retrieveString(forKey: "auth_token") else {
            throw APIError.authenticationRequired
        }
        
        let urlString = "\(baseURL)/\(endpoint)"
        guard let url = URL(string: urlString) else {
            throw APIError.invalidResponse
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        request.setValue(UUID().uuidString, forHTTPHeaderField: "X-Request-ID")
        request.setValue(String(Int(Date().timeIntervalSince1970)), forHTTPHeaderField: "X-Timestamp")
        
        if let body = body {
            let jsonData = try JSONSerialization.data(withJSONObject: body)
            request.httpBody = jsonData
            
            // Sign the request
            let signature = requestSigner.sign(data: jsonData, timestamp: Date())
            request.setValue(signature, forHTTPHeaderField: "X-Signature")
        }
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            return try decoder.decode(T.self, from: data)
        case 401:
            SecureStorage.shared.delete(key: "auth_token")
            throw APIError.authenticationRequired
        case 429:
            throw APIError.rateLimited
        default:
            let message = String(data: data, encoding: .utf8)
            throw APIError.serverError(httpResponse.statusCode, message)
        }
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    private let maxRequests: Int
    private let timeWindow: TimeInterval
    private var requestTimestamps: [Date] = []
    private let lock = NSLock()
    
    init(maxRequests: Int, timeWindow: TimeInterval) {
        self.maxRequests = maxRequests
        self.timeWindow = timeWindow
    }
    
    func allowRequest() -> Bool {
        lock.lock()
        defer { lock.unlock() }
        
        let now = Date()
        requestTimestamps = requestTimestamps.filter { now.timeIntervalSince($0) < timeWindow }
        
        guard requestTimestamps.count < maxRequests else { return false }
        
        requestTimestamps.append(now)
        return true
    }
}

// MARK: - Request Signer

final class RequestSigner {
    
    func sign(data: Data, timestamp: Date) -> String {
        guard let secretData = SecureStorage.shared.retrieve(key: "api_secret") else {
            return ""
        }
        
        let timestampString = String(Int(timestamp.timeIntervalSince1970))
        var payload = data
        payload.append(timestampString.data(using: .utf8) ?? Data())
        
        return hmacSHA256(data: payload, key: secretData)
    }
    
    private func hmacSHA256(data: Data, key: Data) -> String {
        var hmac = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        
        data.withUnsafeBytes { dataBytes in
            key.withUnsafeBytes { keyBytes in
                CCHmac(
                    CCHmacAlgorithm(kCCHmacAlgSHA256),
                    keyBytes.baseAddress,
                    key.count,
                    dataBytes.baseAddress,
                    data.count,
                    &hmac
                )
            }
        }
        
        return hmac.map { String(format: "%02x", $0) }.joined()
    }
}

// MARK: - Audit Logger

final class AuditLogger {
    
    static let shared = AuditLogger()
    
    enum AuditEvent {
        case tradeExecuted(TradeOrder)
        case tradeAttemptBlocked(reason: String)
        case integrityCheckFailed(reasons: [String])
        case authenticationAttempt(success: Bool)
        case biometricAuthentication(success: Bool)
        case sessionStarted
        case sessionEnded
        case suspiciousActivity(description: String)
        case portfolioAccessed
        case fundsTransfer(amount: Decimal)
    }
    
    private let logQueue = DispatchQueue(label: "com.tradingapp.auditlog", qos: .utility)
    
    private init() {}
    
    func log(event: AuditEvent, file: String = #file, function: String = #function, line: Int = #line) {
        logQueue.async {
            let logEntry = self.createLogEntry(event: event, file: file, function: function, line: line)
            self.persistLog(logEntry)
            self.sendToServer(logEntry)
        }
    }
    
    private func createLogEntry(event: AuditEvent, file: String, function: String, line: Int) -> [String: Any] {
        var entry: [String: Any] = [
            "timestamp": ISO8601DateFormatter().string(from: Date()),
            "device_id": UIDevice.current.identifierForVendor?.uuidString ?? "unknown",
            "app_version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            "source_file": (file as NSString).lastPathComponent,
            "source_function": function,
            "source_line": line
        ]
        
        switch event {
        case .tradeExecuted(let order):
            entry["event_type"] = "trade_executed"
            entry["symbol"] = order.symbol
            entry["quantity"] = order.quantity
            entry["order_type"] = order.orderType.rawValue
            entry["side"] = order.side.rawValue
        case .tradeAttemptBlocked(let reason):
            entry["event_type"] = "trade_blocked"
            entry["reason"] = reason
        case .integrityCheckFailed(let reasons):
            entry["event_type"] = "integrity_check_failed"
            entry["reasons"] = reasons
            entry["severity"] = "critical"
        case .authenticationAttempt(let success):
            entry["event_type"] = "auth_attempt"
            entry["success"] = success
        case .biometricAuthentication(let success):
            entry["event_type"] = "biometric_auth"
            entry["success"] = success
        case .sessionStarted:
            entry["event_type"] = "session_started"
        case .sessionEnded:
            entry["event_type"] = "session_ended"
        case .suspiciousActivity(let description):
            entry["event_type"] = "suspicious_activity"
            entry["description"] = description
            entry["severity"] = "high"
        case .portfolioAccessed:
            entry["event_type"] = "portfolio_accessed"
        case .fundsTransfer(let amount):
            entry["event_type"] = "funds_transfer"
            entry["amount"] = "\(amount)"
        }
        
        return entry
    }
    
    private func persistLog(_ entry: [String: Any]) {
        // Store locally for offline scenarios
        guard let data = try? JSONSerialization.data(withJSONObject: entry) else { return }
        let key = "audit_\(UUID().uuidString)"
        SecureStorage.shared.store(key: key, data: data)
    }
    
    private func sendToServer(_ entry: [String: Any]) {
        // Async send to audit server - fire and forget for non-blocking
    }
}

// MARK: - Biometric Authentication

final class BiometricAuthenticator {
    
    static let shared = BiometricAuthenticator()
    
    private init() {}
    
    func authenticate(reason: String) async throws -> Bool {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        context.localizedFallbackTitle = "Use PIN"
        context.touchIDAuthenticationAllowableReuseDuration = 0 // Force fresh authentication
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            AuditLogger.shared.log(event: .biometricAuthentication(success: false))
            throw APIError.biometricFailed
        }
        
        do {
            let success = try await context.evaluatePolicy(
                .deviceOwnerAuthenticationWithBiometrics,
                localizedReason: reason
            )
            AuditLogger.shared.log(event: .biometricAuthentication(success: success))
            return success
        } catch {
            AuditLogger.shared.log(event: .biometricAuthentication(success: false))
            throw APIError.biometricFailed
        }
    }
}

