struct StockQuote: Codable {
    let symbol: String
    let price: Decimal
    let bid: Decimal
    let ask: Decimal
    let volume: Int64
    let timestamp: Date
    let change: Decimal
    let changePercent: Decimal
    let marketCap: Decimal?
    let high52Week: Decimal?
    let low52Week: Decimal?
}

struct TradeOrder: Codable {
    let id: String
    let symbol: String
    let quantity: Int
    let orderType: OrderType
    let side: TradeSide
    let limitPrice: Decimal?
    let stopPrice: Decimal?
    let timeInForce: TimeInForce
    let status: OrderStatus
    let createdAt: Date
    let filledAt: Date?
    let filledPrice: Decimal?
    let commission: Decimal?
    
    enum OrderType: String, Codable {
        case market
        case limit
        case stop
        case stopLimit = "stop_limit"
    }
    
    enum TradeSide: String, Codable {
        case buy
        case sell
    }
    
    enum TimeInForce: String, Codable {
        case day
        case gtc // Good Till Cancelled
        case ioc // Immediate or Cancel
        case fok // Fill or Kill
    }
    
    enum OrderStatus: String, Codable {
        case pending
        case submitted
        case partiallyFilled = "partially_filled"
        case filled
        case cancelled
        case rejected
        case expired
    }
}

struct Portfolio: Codable {
    let accountId: String
    let totalValue: Decimal
    let cashBalance: Decimal
    let buyingPower: Decimal
    let positions: [Position]
    let dayPnL: Decimal
    let totalPnL: Decimal
    let lastUpdated: Date
}

struct Position: Codable {
    let symbol: String
    let quantity: Int
    let averageCost: Decimal
    let currentPrice: Decimal
    let marketValue: Decimal
    let unrealizedPnL: Decimal
    let unrealizedPnLPercent: Decimal
}

struct TradeConfirmation: Codable {
    let orderId: String
    let status: TradeOrder.OrderStatus
    let filledPrice: Decimal?
    let filledQuantity: Int?
    let commission: Decimal?
    let timestamp: Date
}

struct AuthResponse: Codable {
    let token: String
    let refreshToken: String
    let expiresIn: Int
    let userId: String
}

struct AccountBalance: Codable {
    let cashBalance: Decimal
    let buyingPower: Decimal
    let portfolioValue: Decimal
    let marginUsed: Decimal?
}

// MARK: - Trading Service

final class TradingService {
    
    static let shared = TradingService()
    
    private let apiClient = APIClient.shared
    private let integrityChecker = DeviceIntegrityChecker.shared
    private let biometricAuth = BiometricAuthenticator.shared
    
    private init() {}
    
    // MARK: - Authentication
    
    func login(email: String, password: String) async throws -> AuthResponse {
        // Integrity check on login
        let integrity = integrityChecker.performFullIntegrityCheck()
        if integrity.riskLevel >= .high {
            AuditLogger.shared.log(event: .integrityCheckFailed(reasons: integrity.reasons))
            throw APIError.deviceCompromised(reasons: integrity.reasons)
        }
        
        let body: [String: Any] = [
            "email": email,
            "password": password,
            "device_info": getDeviceInfo(),
            "integrity_status": integrity.isCompromised ? "compromised" : "clean"
        ]
        
        let response: AuthResponse = try await apiClient.performAuthenticatedRequest(
            endpoint: "auth/login",
            method: "POST",
            body: body
        )
        
        // Store tokens securely
        SecureStorage.shared.storeString(response.token, forKey: "auth_token")
        SecureStorage.shared.storeString(response.refreshToken, forKey: "refresh_token")
        SecureStorage.shared.storeString(response.userId, forKey: "user_id")
        
        AuditLogger.shared.log(event: .authenticationAttempt(success: true))
        AuditLogger.shared.log(event: .sessionStarted)
        
        return response
    }
    
    func logout() {
        SecureStorage.shared.delete(key: "auth_token")
        SecureStorage.shared.delete(key: "refresh_token")
        SecureStorage.shared.delete(key: "user_id")
        SecureStorage.shared.delete(key: "api_secret")
        AuditLogger.shared.log(event: .sessionEnded)
    }
    
    // MARK: - Market Data
    
    func getQuote(symbol: String) async throws -> StockQuote {
        return try await apiClient.performAuthenticatedRequest(
            endpoint: "market/quote/\(symbol)",
            requiresIntegrityCheck: false
        )
    }
    
    func getQuotes(symbols: [String]) async throws -> [StockQuote] {
        let symbolList = symbols.joined(separator: ",")
        return try await apiClient.performAuthenticatedRequest(
            endpoint: "market/quotes?symbols=\(symbolList)",
            requiresIntegrityCheck: false
        )
    }
    
    // MARK: - Portfolio
    
    func getPortfolio() async throws -> Portfolio {
        AuditLogger.shared.log(event: .portfolioAccessed)
        
        return try await apiClient.performAuthenticatedRequest(
            endpoint: "portfolio",
            requiresIntegrityCheck: true,
            requiredIntegrityLevel: .low
        )
    }
    
    func getAccountBalance() async throws -> AccountBalance {
        return try await apiClient.performAuthenticatedRequest(
            endpoint: "account/balance",
            requiresIntegrityCheck: true,
            requiredIntegrityLevel: .low
        )
    }
    
    func getOrderHistory(limit: Int = 50) async throws -> [TradeOrder] {
        return try await apiClient.performAuthenticatedRequest(
            endpoint: "orders/history?limit=\(limit)",
            requiresIntegrityCheck: true,
            requiredIntegrityLevel: .low
        )
    }
    
    // MARK: - Trade Execution
    
    func executeTrade(
        symbol: String,
        quantity: Int,
        side: TradeOrder.TradeSide,
        orderType: TradeOrder.OrderType,
        limitPrice: Decimal? = nil,
        stopPrice: Decimal? = nil,
        timeInForce: TradeOrder.TimeInForce = .day
    ) async throws -> TradeConfirmation {
        
        // Step 1: Full device integrity check - CRITICAL for trade execution
        let integrity = integrityChecker.performFullIntegrityCheck()
        if integrity.riskLevel >= .medium {
            AuditLogger.shared.log(event: .tradeAttemptBlocked(reason: "Device integrity compromised: \(integrity.reasons)"))
            throw APIError.deviceCompromised(reasons: integrity.reasons)
        }
        
        // Step 2: Biometric authentication for trade execution
        let authenticated = try await biometricAuth.authenticate(
            reason: "Authenticate to execute \(side.rawValue) order for \(quantity) shares of \(symbol)"
        )
        
        guard authenticated else {
            AuditLogger.shared.log(event: .tradeAttemptBlocked(reason: "Biometric authentication failed"))
            throw APIError.biometricFailed
        }
        
        // Step 3: Validate order parameters
        try validateOrder(symbol: symbol, quantity: quantity, side: side, orderType: orderType, limitPrice: limitPrice, stopPrice: stopPrice)
        
        // Step 4: Build and send order
        var body: [String: Any] = [
            "symbol": symbol.uppercased(),
            "quantity": quantity,
            "side": side.rawValue,
            "order_type": orderType.rawValue,
            "time_in_force": timeInForce.rawValue,
            "client_order_id": UUID().uuidString,
            "device_integrity_verified": true,
            "biometric_verified": true
        ]
        
        if let limitPrice = limitPrice {
            body["limit_price"] = "\(limitPrice)"
        }
        if let stopPrice = stopPrice {
            body["stop_price"] = "\(stopPrice)"
        }
        
        let confirmation: TradeConfirmation = try await apiClient.performAuthenticatedRequest(
            endpoint: "orders",
            method: "POST",
            body: body,
            requiresIntegrityCheck: true,
            requiredIntegrityLevel: .none
        )
        
        // Log the trade
        let order = TradeOrder(
            id: confirmation.orderId,
            symbol: symbol,
            quantity: quantity,
            orderType: orderType,
            side: side,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            timeInForce: timeInForce,
            status: confirmation.status,
            createdAt: Date(),
            filledAt: nil,
            filledPrice: confirmation.filledPrice,
            commission: confirmation.commission
        )
        AuditLogger.shared.log(event: .tradeExecuted(order))
        
        return confirmation
    }
    
    func cancelOrder(orderId: String) async throws -> TradeConfirmation {
        // Integrity check for order cancellation
        let integrity = integrityChecker.performFullIntegrityCheck()
        if integrity.riskLevel >= .medium {
            throw APIError.deviceCompromised(reasons: integrity.reasons)
        }
        
        return try await apiClient.performAuthenticatedRequest(
            endpoint: "orders/\(orderId)/cancel",
            method: "POST",
            requiresIntegrityCheck: true,
            requiredIntegrityLevel: .none
        )
    }
    
    // MARK: - Fund Transfers
    
    func transferFunds(amount: Decimal, direction: String) async throws -> [String: Any] {
        // Highest security for fund transfers
        let integrity = integrityChecker.performFullIntegrityCheck()
        if integrity.riskLevel >= .low {
            AuditLogger.shared.log(event: .suspiciousActivity(description: "Fund transfer attempted on potentially compromised device"))
            throw APIError.deviceCompromised(reasons: integrity.reasons)
        }
        
        let authenticated = try await biometricAuth.authenticate(
            reason: "Authenticate to transfer $\(amount)"
        )
        
        guard authenticated else {
            throw APIError.biometricFailed
        }
        
        AuditLogger.shared.log(event: .fundsTransfer(amount: amount))
        
        let body: [String: Any] = [
            "amount": "\(amount)",
            "direction": direction,
            "device_integrity_verified": true,
            "biometric_verified": true
        ]
        
        return try await apiClient.performAuthenticatedRequest(
            endpoint: "account/transfer",
            method: "POST",
            body: body,
            requiresIntegrityCheck: true,
            requiredIntegrityLevel: .none
        )
    }
    
    // MARK: - Validation
    
    private func validateOrder(
        symbol: String,
        quantity: Int,
        side: TradeOrder.TradeSide,
        orderType: TradeOrder.OrderType,
        limitPrice: Decimal?,
        stopPrice: Decimal?
    ) throws {
        guard !symbol.isEmpty else {
            throw APIError.invalidOrder
        }
        
        guard quantity > 0 && quantity <= 100000 else {
            throw APIError.invalidOrder
        }
        
        // Validate symbol format (1-5 uppercase letters)
        let symbolRegex = try NSRegularExpression(pattern: "^[A-Z]{1,5}$")
        let range = NSRange(symbol.startIndex..., in: symbol.uppercased())
        guard symbolRegex.firstMatch(in: symbol.uppercased(), range: range) != nil else {
            throw APIError.invalidOrder
        }
        
        switch orderType {
        case .limit:
            guard let price = limitPrice, price > 0 else {
                throw APIError.invalidOrder
            }
        case .stop:
            guard let price = stopPrice, price > 0 else {
                throw APIError.invalidOrder
            }
        case .stopLimit:
            guard let lp = limitPrice, lp > 0, let sp = stopPrice, sp > 0 else {
                throw APIError.invalidOrder
            }
        case .market:
            break
        }
    }
    
    // MARK: - Device Info
    
    private func getDeviceInfo() -> [String: String] {
        return [
            "model": UIDevice.current.model,
            "system_version": UIDevice.current.systemVersion,
            "device_id": UIDevice.current.identifierForVendor?.uuidString ?? "unknown",
            "app_version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            "build": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "unknown"
        ]
    }
}

// MARK: - WebSocket Manager for Real-Time Data

final class WebSocketManager: NSObject, URLSessionWebSocketDelegate {
    
    static let shared = WebSocketManager()
    
    private var webSocket: URLSessionWebSocketTask?
    private var isConnected = false
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    
    var onQuoteUpdate: ((StockQuote) -> Void)?
    var onOrderUpdate: ((TradeOrder) -> Void)?
    var onConnectionStatusChange: ((Bool) -> Void)?
    
    private override init() {
        super.init()
    }
    
    func connect() {
        // Integrity check before establishing real-time connection
        let integrity = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        if integrity.riskLevel >= .high {
            AuditLogger.shared.log(event: .suspiciousActivity(description: "WebSocket connection blocked on compromised device"))
            return
        }
        
        guard let token = SecureStorage.shared.retrieveString(forKey: "auth_token") else { return }
        
        guard let url = URL(string: "wss://ws.tradingplatform.com/v1/stream?token=\(token)") else { return }
        
        let config = URLSessionConfiguration.default
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        let session = URLSession(configuration: config, delegate: self, delegateQueue: nil)
        
        webSocket = session.webSocketTask(with: url)
        webSocket?.resume()
        
        receiveMessage()
    }
    
    func disconnect() {
        webSocket?.cancel(with: .goingAway, reason: nil)
        isConnected = false
        onConnectionStatusChange?(false)
    }
    
    func subscribe(symbols: [String]) {
        guard isConnected else { return }
        
        let message: [String: Any] = [
            "action": "subscribe",
            "symbols": symbols
        ]
        
        guard let data = try? JSONSerialization.data(withJSONObject: message) else { return }
        let wsMessage = URLSessionWebSocketTask.Message.data(data)
        
        webSocket?.send(wsMessage) { error in
            if let error = error {
                print("WebSocket send error: \(error)")
            }
        }
    }
    
    func unsubscribe(symbols: [String]) {
        guard isConnected else { return }
        
        let message: [String: Any] = [
            "action": "unsubscribe",
            "symbols": symbols
        ]
        
        guard let data = try? JSONSerialization.data(withJSONObject: message) else { return }
        let wsMessage = URLSessionWebSocketTask.Message.data(data)
        
        webSocket?.send(wsMessage) { _ in }
    }
    
    private func receiveMessage() {
        webSocket?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .data(let data):
                    self?.handleMessage(data: data)
                case .string(let text):
                    if let data = text.data(using: .utf8) {
                        self?.handleMessage(data: data)
                    }
                @unknown default:
                    break
                }
                self?.receiveMessage()
                
            case .failure(let error):
                print("WebSocket receive error: \(error)")
                self?.handleDisconnection()
            }
        }
    }
    
    private func handleMessage(data: Data) {
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        
        if let quote = try? decoder.decode(StockQuote.self, from: data) {
            DispatchQueue.main.async {
                self.onQuoteUpdate?(quote)
            }
        } else if let order = try? decoder.decode(TradeOrder.self, from: data) {
            DispatchQueue.main.async {
                self.onOrderUpdate?(order)
            }
        }
    }
    
    private func handleDisconnection() {
        isConnected = false
        DispatchQueue.main.async {
            self.onConnectionStatusChange?(false)
        }
        
        guard reconnectAttempts < maxReconnectAttempts else {
            AuditLogger.shared.log(event: .suspiciousActivity(description: "WebSocket max reconnect attempts reached"))
            return
        }
        
        reconnectAttempts += 1
        let delay = Double(min(reconnectAttempts * 2, 30))
        
        DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
            self?.connect()
        }
    }
    
    // MARK: - URLSessionWebSocketDelegate
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didOpenWithProtocol protocol: String?) {
        isConnected = true
        reconnectAttempts = 0
        DispatchQueue.main.async {
            self.onConnectionStatusChange?(true)
        }
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        handleDisconnection()
    }
}

// MARK: - App Security Coordinator

final class AppSecurityCoordinator {
    
    static let shared = AppSecurityCoordinator()
    
    private var integrityCheckTimer: Timer?
    private var lastIntegrityCheck: Date?
    private let integrityCheckInterval: TimeInterval = 300 // 5 minutes
    
    private init() {}
    
    func startSecurityMonitoring() {
        performInitialSecurityCheck()
        startPeriodicIntegrityChecks()
        setupBackgroundProtection()
    }
    
    func stopSecurityMonitoring() {
        integrityCheckTimer?.invalidate()
        integrityCheckTimer = nil
    }
    
    private func performInitialSecurityCheck() {
        let result = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        
        if result.riskLevel >= .critical {
            // Critical compromise - block all functionality
            AuditLogger.shared.log(event: .integrityCheckFailed(reasons: result.reasons))
            handleCriticalCompromise(result)
        } else if result.riskLevel >= .high {
            // High risk - allow read-only, block trades
            AuditLogger.shared.log(event: .integrityCheckFailed(reasons: result.reasons))
            handleHighRiskCompromise(result)
        } else if result.isCompromised {
            // Low/medium risk - log and allow with warnings
            AuditLogger.shared.log(event: .suspiciousActivity(description: "Low-risk integrity issues: \(result.reasons)"))
        }
    }
    
    private func startPeriodicIntegrityChecks() {
        integrityCheckTimer = Timer.scheduledTimer(withTimeInterval: integrityCheckInterval, repeats: true) { [weak self] _ in
            self?.performPeriodicCheck()
        }
    }
    
    private func performPeriodicCheck() {
        let result = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        lastIntegrityCheck = Date()
        
        if result.riskLevel >= .high {
            AuditLogger.shared.log(event: .integrityCheckFailed(reasons: result.reasons))
            
            // Disconnect real-time feeds
            WebSocketManager.shared.disconnect()
            
            // Notify the app to restrict functionality
            NotificationCenter.default.post(
                name: .deviceIntegrityCompromised,
                object: nil,
                userInfo: ["result": result]
            )
        }
    }
    
    private func handleCriticalCompromise(_ result: DeviceIntegrityChecker.IntegrityResult) {
        // Force logout
        TradingService.shared.logout()
        WebSocketManager.shared.disconnect()
        
        NotificationCenter.default.post(
            name: .deviceIntegrityCritical,
            object: nil,
            userInfo: ["result": result]
        )
    }
    
    private func handleHighRiskCompromise(_ result: DeviceIntegrityChecker.IntegrityResult) {
        NotificationCenter.default.post(
            name: .deviceIntegrityCompromised,
            object: nil,
            userInfo: ["result": result]
        )
    }
    
    private func setupBackgroundProtection() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(appWillResignActive),
            name: UIApplication.willResignActiveNotification,
            object: nil
        )
        
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(appDidBecomeActive),
            name: UIApplication.didBecomeActiveNotification,
            object: nil
        )
    }
    
    @objc private func appWillResignActive() {
        // Add screen protection overlay to prevent screenshot of sensitive data
        addScreenProtection()
    }
    
    @objc private func appDidBecomeActive() {
        removeScreenProtection()
        
        // Re-check integrity when app becomes active
        performPeriodicCheck()
    }
    
    private func addScreenProtection() {
        guard let window = UIApplication.shared.connectedScenes
            .compactMap({ $0 as? UIWindowScene })
            .first?.windows.first else { return }
        
        let blurEffect = UIBlurEffect(style: .light)
        let blurView = UIVisualEffectView(effect: blurEffect)
        blurView.frame = window.bounds
        blurView.tag = 999
        window.addSubview(blurView)
    }
    
    private func removeScreenProtection() {
        guard let window = UIApplication.shared.connectedScenes
            .compactMap({ $0 as? UIWindowScene })
            .first?.windows.first else { return }
        
        window.viewWithTag(999)?.removeFromSuperview()
    }
}

// MARK: - Notification Names

extension Notification.Name {
    static let deviceIntegrityCompromised = Notification.Name("deviceIntegrityCompromised")
    static let deviceIntegrityCritical = Notification.Name("deviceIntegrityCritical")
}

// MARK: - View Controllers

class TradeViewController: UIViewController {
    
    private let tradingService = TradingService.shared
    private var isDeviceCompromised = false
    
    private let symbolTextField = UITextField()
    private let quantityTextField = UITextField()
    private let orderTypeSegment = UISegmentedControl(items: ["Market", "Limit", "Stop"])
    private let sideSegment = UISegmentedControl(items: ["Buy", "Sell"])
    private let limitPriceTextField = UITextField()
    private let executeButton = UIButton(type: .system)
    private let statusLabel = UILabel()
    private let quoteLabel = UILabel()
    private let activityIndicator = UIActivityIndicatorView(style: .large)
    private let warningBanner = UIView()
    private let warningLabel = UILabel()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupSecurityObservers()
        
        // Initial integrity check
        checkDeviceIntegrity()
    }
    
    deinit {
        NotificationCenter.default.removeObserver(self)
    }
    
    private func setupSecurityObservers() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleIntegrityCompromised),
            name: .deviceIntegrityCompromised,
            object: nil
        )
        
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleCriticalIntegrity),
            name: .deviceIntegrityCritical,
            object: nil
        )
    }
    
    @objc private func handleIntegrityCompromised(_ notification: Notification) {
        isDeviceCompromised = true
        DispatchQueue.main.async { [weak self] in
            self?.executeButton.isEnabled = false
            self?.showWarningBanner(message: "Trading is restricted. Device security issue detected.")
        }
    }
    
    @objc private func handleCriticalIntegrity(_ notification: Notification) {
        DispatchQueue.main.async { [weak self] in
            self?.showCriticalAlert()
        }
    }
    
    private func checkDeviceIntegrity() {
        let result = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        if result.riskLevel >= .medium {
            isDeviceCompromised = true
            executeButton.isEnabled = false
            showWarningBanner(message: "Trading is restricted due to device security concerns.")
        }
    }
    
    private func showWarningBanner(message: String) {
        warningBanner.isHidden = false
        warningLabel.text = message
    }
    
    private func showCriticalAlert() {
        let alert = UIAlertController(
            title: "Security Alert",
            message: "A critical security issue has been detected on this device. For your protection, you have been logged out. Please contact support if you believe this is an error.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            // Navigate to login screen
        })
        present(alert, animated: true)
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Trade"
        
        // Warning banner
        warningBanner.backgroundColor = .systemRed.withAlphaComponent(0.9)
        warningBanner.isHidden = true
        warningBanner.translatesAutoresizingMaskIntoConstraints = false
        
        warningLabel.textColor = .white
        warningLabel.font = .systemFont(ofSize: 14, weight: .semibold)
        warningLabel.numberOfLines = 0
        warningLabel.textAlignment = .center
        warningLabel.translatesAutoresizingMaskIntoConstraints = false
        warningBanner.addSubview(warningLabel)
        
        // Configure text fields
        symbolTextField.placeholder = "Symbol (e.g., AAPL)"
        symbolTextField.borderStyle = .roundedRect
        symbolTextField.autocapitalizationType = .allCharacters
        symbolTextField.textContentType = .none
        symbolTextField.isSecureTextEntry = false
        
        quantityTextField.placeholder = "Quantity"
        quantityTextField.borderStyle = .roundedRect
        quantityTextField.keyboardType = .numberPad
        
        limitPriceTextField.placeholder = "Limit Price (optional)"
        limitPriceTextField.borderStyle = .roundedRect
        limitPriceTextField.keyboardType = .decimalPad
        limitPriceTextField.isHidden = true
        
        // Configure segments
        orderTypeSegment.selectedSegmentIndex = 0
        orderTypeSegment.addTarget(self, action: #selector(orderTypeChanged), for: .valueChanged)
        
        sideSegment.selectedSegmentIndex = 0
        
        // Configure button
        executeButton.setTitle("Execute Trade", for: .normal)
        executeButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .bold)
        executeButton.backgroundColor = .systemGreen
        executeButton.setTitleColor(.white, for: .normal)
        executeButton.layer.cornerRadius = 12
        executeButton.addTarget(self, action: #selector(executeTrade), for: .touchUpInside)
        
        // Quote label
        quoteLabel.font = .systemFont(ofSize: 16)
        quoteLabel.textAlignment = .center
        quoteLabel.numberOfLines = 0
        
        // Status label
        statusLabel.font = .systemFont(ofSize: 14)
        statusLabel.textAlignment = .center
        statusLabel.numberOfLines = 0
        statusLabel.textColor = .secondaryLabel
        
        // Activity indicator
        activityIndicator.hidesWhenStopped = true
        
        // Layout
        let stackView = UIStackView(arrangedSubviews: [
            symbolTextField,
            quoteLabel,
            quantityTextField,
            orderTypeSegment,
            sideSegment,
            limitPriceTextField,
            executeButton,
            activityIndicator,
            statusLabel
        ])
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(warningBanner)
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            warningBanner.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            warningBanner.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            warningBanner.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            
            warningLabel.topAnchor.constraint(equalTo: warningBanner.topAnchor, constant: 8),
            warningLabel.bottomAnchor.constraint(equalTo: warningBanner.bottomAnchor, constant: -8),
            warningLabel.leadingAnchor.constraint(equalTo: warningBanner.leadingAnchor, constant: 16),
            warningLabel.trailingAnchor.constraint(equalTo: warningBanner.trailingAnchor, constant: -16),
            
            stackView.topAnchor.constraint(equalTo: warningBanner.bottomAnchor, constant: 20),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            executeButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        // Add symbol lookup on editing end
        symbolTextField.addTarget(self, action: #selector(symbolChanged), for: .editingDidEnd)
    }
    
    @objc private func orderTypeChanged() {
        limitPriceTextField.isHidden = orderTypeSegment.selectedSegmentIndex == 0
    }
    
    @objc private func symbolChanged() {
        guard let symbol = symbolTextField.text, !symbol.isEmpty else { return }
        
        Task {
            do {
                let quote = try await tradingService.getQuote(symbol: symbol)
                DispatchQueue.main.async { [weak self] in
                    self?.quoteLabel.text = "\(quote.symbol): $\(quote.price) (\(quote.changePercent)%)"
                    self?.quoteLabel.textColor = quote.change >= 0 ? .systemGreen : .systemRed
                }
            } catch {
                DispatchQueue.main.async { [weak self] in
                    self?.quoteLabel.text = "Unable to fetch quote"
                    self?.quoteLabel.textColor = .systemRed
                }
            }
        }
    }
    
